#!/usr/bin/env python3
"""Reproduction script for 10_train_eval_gap. Generated by gen_research_figures.py."""
import json, sys
from pathlib import Path
import matplotlib; matplotlib.use("Agg")
import matplotlib.pyplot as plt
import numpy as np

# Style
plt.rcParams.update({
    "font.family": "serif", "font.size": 10, "axes.titlesize": 12,
    "axes.labelsize": 11, "legend.fontsize": 9, "xtick.labelsize": 9,
    "ytick.labelsize": 9, "savefig.dpi": 600, "savefig.bbox": "tight",
    "pdf.fonttype": 42, "ps.fonttype": 42,
    "axes.spines.top": False, "axes.spines.right": False,
})

CB_GREEN = "#009E73"; CB_RED = "#D55E00"; CB_BLUE = "#0072B2"
CB_ORANGE = "#E69F00"; CB_PURPLE = "#CC79A7"; CB_SKY = "#56B4E9"
MODEL_COLORS = {"GPT-OSS-20B": CB_BLUE, "Qwen3-30B-Instruct": CB_GREEN, "Qwen3-30B-Think": CB_RED}
MODEL_MARKERS = {"GPT-OSS-20B": "o", "Qwen3-30B-Instruct": "s", "Qwen3-30B-Think": "^"}

DATA_ROOT = Path("/tmp/tinker-examples/rlvr")
RUNS = {
    "GPT-OSS-20B": DATA_ROOT / "gptoss-20b-v3b" / "metrics.jsonl",
    "Qwen3-30B-Instruct": DATA_ROOT / "qwen3-30b-instruct-v3b" / "metrics.jsonl",
    "Qwen3-30B-Think": DATA_ROOT / "qwen3-30b-think-v3b" / "metrics.jsonl",
}

def load_all():
    result = {}
    for name, path in RUNS.items():
        data = [json.loads(l) for l in open(path)]
        train = [d for d in data if "env/all/correct" in d]
        evl = [d for d in data if "test/test/env/all/correct" in d]
        result[name] = (train, evl)
    return result

def save(fig, name):
    fig.savefig(f"{name}.png", dpi=600, bbox_inches="tight")
    fig.savefig(f"{name}.pdf", bbox_inches="tight")
    print(f"Saved {name}.png and {name}.pdf")

# --- Figure function ---
def fig10_train_eval_gap(all_data):
    fig, ax = plt.subplots(figsize=(8, 5))
    for name, (train, evl) in all_data.items():
        color = MODEL_COLORS[name]
        eval_steps = [d["step"] for d in evl]
        eval_correct = {d["step"]: d["test/test/env/all/correct"] for d in evl}
        train_correct = {d["step"]: d["env/all/correct"] for d in train}

        gaps = []
        steps_plot = []
        for step in eval_steps:
            if step in train_correct:
                gap = eval_correct[step] - train_correct[step]
                gaps.append(gap)
                steps_plot.append(step)

        if steps_plot:
            ax.plot(steps_plot, gaps, color=color, marker=MODEL_MARKERS[name],
                    linewidth=2, markersize=7, label=name)

    ax.axhline(0, color="gray", linewidth=0.8, linestyle=":")
    ax.set_xlabel("Training step")
    ax.set_ylabel("Eval \u2212 Train accuracy gap")
    ax.set_title("Generalization Gap Over Training")
    ax.legend()
    ax.grid(axis="y", alpha=0.3)

    ax.text(0.98, 0.95, "positive gap expected (eval uses lower temp)",
            transform=ax.transAxes, ha="right", va="top", fontsize=8, color="gray")
    ax.text(0.98, 0.05, "negative gap = eval-specific failure",
            transform=ax.transAxes, ha="right", va="bottom", fontsize=8, color="gray")
    save(fig, "10_train_eval_gap", fig10_train_eval_gap)


if __name__ == '__main__':
    all_data = load_all()
    fig10_train_eval_gap(all_data)
